import { READING_PASSAGE_VOCAB_GT } from './readingPassageVocabGt'

export type ReadingPassageVocabItem = {
  word: string
  thaiMeaning: string
  example?: string
}

/** Strip exam prefixes and punctuation so titles match curated vocab keys. */
export const normalizeReadingPassageTitle = (title: string) =>
  String(title || '')
    .toLowerCase()
    .replace(
      /^(cambridge \d+ test\s*\d+ passage\s*\d+\s*[-–—:]\s*|general training full test \d+\s*[-–—:]\s*|ielts academic reading[^-:\n]{0,80}passage\s*\d+\s+|custom reading\s+|exercise\s*\d+\s+|ielts reading practice\s+)/i,
      ''
    )
    .replace(/[^a-z0-9 ]/g, '')
    .replace(/\s+/g, ' ')
    .trim()

const isGenericReadingPassageTitle = (normalized: string) =>
  !normalized ||
  /^(reading )?passage \d+$/.test(normalized) ||
  /^section \d+$/.test(normalized) ||
  /^questions? \d+(\s*\d+)?$/.test(normalized)

/** Prefer phrasal / multi-word items; keep up to ~40 highlights per passage. */
export const selectReadingPassageVocab = (
  items: ReadingPassageVocabItem[],
  max = 40
): ReadingPassageVocabItem[] => {
  if (!items.length) return []
  if (items.length <= max) return items
  const ranked = items.map((item, index) => {
    const word = String(item.word || '').trim()
    const parts = word.split(/\s+/).filter(Boolean).length
    const phrasalBonus = parts >= 2 || word.includes('-') ? 1000 : 0
    return { item, index, score: phrasalBonus + word.length }
  })
  ranked.sort((a, b) => b.score - a.score || a.index - b.index)
  return ranked.slice(0, max).map((row) => row.item)
}

const lookupVocabKeyByTitle = (title: string): string => {
  const normalized = normalizeReadingPassageTitle(title)
  if (isGenericReadingPassageTitle(normalized)) return ''

  if (READING_PASSAGE_VOCAB[normalized]?.length) return normalized

  let bestKey = ''
  let bestScore = 0
  for (const key of Object.keys(READING_PASSAGE_VOCAB)) {
    if (key.length < 8) continue

    if (normalized === key) return key

    if (normalized.includes(key) || key.includes(normalized)) {
      const shorter = Math.min(key.length, normalized.length)
      const longer = Math.max(key.length, normalized.length)
      const coverage = shorter / longer
      // Avoid "passage 1" matching "...passage 1 the return of the bald eagle"
      if (coverage < 0.45 && shorter < 18) continue
      const score = shorter + coverage * 80 + 200
      if (score > bestScore) {
        bestScore = score
        bestKey = key
      }
      continue
    }

    const nTokens = new Set(normalized.split(' ').filter((token) => token.length > 3))
    const kTokens = key.split(' ').filter((token) => token.length > 3)
    if (!nTokens.size || kTokens.length < 2) continue
    const overlap = kTokens.filter((token) => nTokens.has(token)).length
    const ratio = overlap / kTokens.length
    if (overlap >= 2 && ratio >= 0.55) {
      const score = overlap * 40 + ratio * 30
      if (score > bestScore) {
        bestScore = score
        bestKey = key
      }
    }
  }
  return bestKey
}

const lookupVocabKeyByPassageText = (passageText: string): string => {
  const lower = String(passageText || '').toLowerCase()
  if (lower.length < 120) return ''

  let bestKey = ''
  let bestHits = 0
  for (const [key, items] of Object.entries(READING_PASSAGE_VOCAB)) {
    let hits = 0
    for (const item of items) {
      const word = String(item.word || '').trim().toLowerCase()
      if (word.length < 4) continue
      if (lower.includes(word)) hits += 1
    }
    if (hits > bestHits) {
      bestHits = hits
      bestKey = key
    }
  }
  return bestHits >= 4 ? bestKey : ''
}

