// Merge General Training curated vocab (≈40 items per passage).
Object.assign(READING_PASSAGE_VOCAB, READING_PASSAGE_VOCAB_GT)

export type GetReadingPassageVocabOptions = {
  fallbackTitles?: Array<string | null | undefined>
  passageText?: string
}

export const getReadingPassageVocab = (
  title: string,
  options?: GetReadingPassageVocabOptions
): ReadingPassageVocabItem[] => {
  const titles = [title, ...(options?.fallbackTitles || [])]
  for (const candidate of titles) {
    if (!candidate) continue
    const key = lookupVocabKeyByTitle(String(candidate))
    if (key && READING_PASSAGE_VOCAB[key]?.length) {
      return selectReadingPassageVocab(READING_PASSAGE_VOCAB[key])
    }
  }

  if (options?.passageText) {
    const key = lookupVocabKeyByPassageText(options.passageText)
    if (key && READING_PASSAGE_VOCAB[key]?.length) {
      return selectReadingPassageVocab(READING_PASSAGE_VOCAB[key])
    }
  }

  return []
}
